const raw = $json.body ?? $json;
const payload = (raw && typeof raw === 'object') ? (raw.data ?? raw) : {};
const headers = $json.headers || {};
const executionId = (typeof $execution !== 'undefined' && $execution?.id) ? String($execution.id) : String(Date.now());
const CONFIG_VERSION = 'wf-c-manychat-intake-clint@fase2-etapa6-2026-03-06';
