const DEFAULT_LIST_KEY = 'cj_ppt_webinar';

const LIST_CONFIGS = Object.freeze({
  cj_ppt_webinar: Object.freeze({
    origin_name: 'Perpétuo Webinário',
    origin_id: 'bd1bd846-0c87-4acb-b221-d7f8d2089e68',
    tag_name: 'cj-ppt-webinar',
    lista_origem: 'cj-ppt-webinar',
    produto: 'VDE Carreiras Jurídicas Ciclo Prioritário',
    value: 2557,
    clint_base_url: 'https://api.clint.digital/v1'
  })
});

const GLOBAL_INPUT_ALIASES = Object.freeze({
  first_name: ['first_name', 'first name'],
  last_name: ['last_name', 'last name'],
  list_key: [
    'list_key',
    'lista_key',
    'lista_origem',
    'lista origem',
    'origem_lista',
    'origem lista',
    'campaign_key',
    'campaign key'
  ],
  nome: ['nome', 'name', 'full_name', 'full name', 'first_name'],
  email: ['email', 'e-mail', 'mail', 'email_address', 'email address'],
  whatsapp: [
    'whatsapp',
    'whatsapp_phone',
    'whatsapp phone',
    'phone',
    'telefone',
    'celular',
    'auth_phone',
    'auth phone'
  ],
  carreira_pretendida: [
    'carreira_pretendida',
    'carreira pretendida'
  ],
  utm_source: ['utm_source', 'utm source', 'utmsource'],
  utm_medium: ['utm_medium', 'utm medium', 'utmmedium'],
  utm_campaign: ['utm_campaign', 'utm campaign', 'utmcampaign'],
  utm_term: ['utm_term', 'utm term', 'utmterm'],
  utm_content: ['utm_content', 'utm content', 'utmcontent']
});

const LIST_INPUT_ALIASES = Object.freeze({
  cj_ppt_webinar: Object.freeze({
    carreira_pretendida: [
      'carreira_concursos',
      'carreira concursos'
    ]
  })
});

function normalizeKey(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[?!:;,.()\[\]'"%]/g, '')
    .replace(/[-_/]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeValue(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return String(value).trim();
  }

  if (Array.isArray(value)) {
    for (const item of value) {
      const extracted = normalizeValue(item);
      if (extracted) return extracted;
    }
    return '';
  }

  if (typeof value === 'object') {
    const priorityKeys = ['value', 'text', 'label', 'name', 'phone', 'email'];
    for (const key of priorityKeys) {
      if (Object.prototype.hasOwnProperty.call(value, key)) {
        const extracted = normalizeValue(value[key]);
        if (extracted) return extracted;
      }
    }
  }

  return '';
}

function normalizeListKey(value) {
  const base = normalizeKey(value);
  return base ? base.replace(/\s+/g, '_') : '';
}

function digitsOnly(value) {
  return String(value || '').replace(/\D/g, '');
}

function cleanObject(obj) {
  return Object.fromEntries(
    Object.entries(obj || {}).filter(([, value]) => value !== undefined && value !== null && String(value).trim() !== '')
  );
}

function maskEmail(value) {
  const email = normalizeValue(value).toLowerCase();
  const [localPart, domainPart] = email.split('@');

  if (!localPart || !domainPart) {
    return email ? '[REDACTED_EMAIL]' : '';
  }

  const localMasked = `${localPart[0] || '*'}${'*'.repeat(Math.max(localPart.length - 1, 1))}`;
  const [domainRoot, ...domainSuffix] = domainPart.split('.');
  const domainMasked = domainRoot ? `${domainRoot[0]}***` : '***';
  const suffix = domainSuffix.length ? `.${domainSuffix.join('.')}` : '';

  return `${localMasked}@${domainMasked}${suffix}`;
}

function maskPhone(value) {
  const digits = digitsOnly(value);
  if (!digits) {
    return '';
  }

  if (digits.length <= 4) {
    return '*'.repeat(digits.length);
  }

  return `${'*'.repeat(digits.length - 4)}${digits.slice(-4)}`;
}

function sanitizePrimitiveByKey(key, value) {
  const keyNorm = normalizeKey(key);
  const asString = normalizeValue(value);

  if (!asString) {
    return asString;
  }

  if (/(token|authorization|password|secret|api key|api token)/.test(keyNorm)) {
    return '[REDACTED]';
  }

  if (/(email|mail)/.test(keyNorm)) {
    return maskEmail(asString);
  }

  if (/(phone|whatsapp|telefone|celular|ddi)/.test(keyNorm)) {
    return maskPhone(asString);
  }

  return asString;
}

function sanitizeForLogs(value, key = '', depth = 0) {
  if (depth > 6) {
    return '[TRUNCATED]';
  }

  if (value === undefined || value === null) {
    return value;
  }

  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return sanitizePrimitiveByKey(key, value);
  }

  if (Array.isArray(value)) {
    return value.slice(0, 50).map((item) => sanitizeForLogs(item, key, depth + 1));
  }

  if (typeof value === 'object') {
    return Object.fromEntries(
      Object.entries(value).slice(0, 100).map(([entryKey, entryValue]) => [
        entryKey,
        sanitizeForLogs(entryValue, entryKey, depth + 1)
      ])
    );
  }

  return '[UNSUPPORTED_VALUE]';
}

function sanitizePayloadForLogs(payloadObject) {
  return sanitizeForLogs(payloadObject, 'payload');
}

function buildAuditMetadata({ status, step, httpStatus, listKey, extra = {} }) {
  return cleanObject({
    source: 'manychat_webhook',
    status,
    step,
    http_status: httpStatus,
    execution_id: executionId,
    list_key: listKey,
    config_version: CONFIG_VERSION,
    received_at: receivedAt,
    recorded_at: new Date().toISOString(),
    ...extra
  });
}

function normalizePhone(rawPhone) {
  const phoneClean = digitsOnly(rawPhone);
  if (!phoneClean) return { ddi: '', phone: '', whatsapp_digits: '' };

  if (phoneClean.startsWith('55') && phoneClean.length > 11) {
    return {
      ddi: '+55',
      phone: phoneClean.slice(2),
      whatsapp_digits: phoneClean
    };
  }

  if (phoneClean.length === 10 || phoneClean.length === 11) {
    return {
      ddi: '+55',
      phone: phoneClean,
      whatsapp_digits: phoneClean
    };
  }

  return { ddi: '', phone: '', whatsapp_digits: phoneClean };
}

function collectPayloadContainers(payloadObject) {
  return [
    payloadObject,
    payloadObject.fields || {},
    payloadObject.custom_fields || {},
    payloadObject.customFields || {},
    payloadObject.contact || {},
    payloadObject.subscriber || {},
    payloadObject.variables || {}
  ].filter((item) => item && typeof item === 'object' && !Array.isArray(item));
}

function createAliasPicker(containers) {
  return function pickValue(aliases) {
    const normalizedAliases = new Set((aliases || []).map((alias) => normalizeKey(alias)).filter(Boolean));

    if (!normalizedAliases.size) {
      return '';
    }

    for (const container of containers) {
      for (const [rawKey, rawValue] of Object.entries(container || {})) {
        if (!normalizedAliases.has(normalizeKey(rawKey))) {
          continue;
        }

        const cleaned = normalizeValue(rawValue);
        if (cleaned) {
          return cleaned;
        }
      }
    }

    return '';
  };
}

function dedupeAliases(aliases) {
  const seen = new Set();
  const result = [];

  for (const alias of aliases || []) {
    const aliasText = String(alias || '').trim();
    if (!aliasText) {
      continue;
    }

    const normalizedAlias = normalizeKey(aliasText);
    if (!normalizedAlias || seen.has(normalizedAlias)) {
      continue;
    }

    seen.add(normalizedAlias);
    result.push(aliasText);
  }

  return result;
}

function mergeInputAliases(globalAliases, listAliases) {
  const merged = {};
  const keySet = new Set([
    ...Object.keys(globalAliases || {}),
    ...Object.keys(listAliases || {})
  ]);

  for (const key of keySet) {
    const listEntries = Array.isArray(listAliases?.[key]) ? listAliases[key] : [];
    const globalEntries = Array.isArray(globalAliases?.[key]) ? globalAliases[key] : [];
    merged[key] = dedupeAliases([...listEntries, ...globalEntries]);
  }

  return merged;
}

function resolveListConfig(pickValue) {
  const requestedListKeyRaw = pickValue(GLOBAL_INPUT_ALIASES.list_key);
  const requestedListKey = normalizeListKey(requestedListKeyRaw || DEFAULT_LIST_KEY);
  const hasListConfig = Boolean(LIST_CONFIGS[requestedListKey]);
  const resolvedListKey = hasListConfig ? requestedListKey : DEFAULT_LIST_KEY;
  const inputAliases = mergeInputAliases(
    GLOBAL_INPUT_ALIASES,
    LIST_INPUT_ALIASES[resolvedListKey] || {}
  );

  return {
    requested_list_key: requestedListKeyRaw || '',
    list_key: resolvedListKey,
    list_key_fallback_applied: !hasListConfig,
    input_aliases: inputAliases,
    workflow_config: {
      ...LIST_CONFIGS[resolvedListKey],
      list_key: resolvedListKey,
      config_version: CONFIG_VERSION
    }
  };
}

function buildNormalizedPayload(pickValue, inputAliases) {
  const firstName = pickValue(inputAliases.first_name || []);
  const lastName = pickValue(inputAliases.last_name || []);
  const fullNameFallback = [firstName, lastName].filter(Boolean).join(' ').trim();

  const nome = pickValue(inputAliases.nome || []) || fullNameFallback;
  const email = pickValue(inputAliases.email || []).toLowerCase();
  const whatsappRaw = pickValue(inputAliases.whatsapp || []);
  const carreiraPretendida = pickValue(inputAliases.carreira_pretendida || []);
  const phonePayload = normalizePhone(whatsappRaw);

  return {
    nome,
    email,
    whatsapp: whatsappRaw,
    whatsapp_digits: phonePayload.whatsapp_digits,
    ddi: phonePayload.ddi,
    phone: phonePayload.phone,
    carreira_pretendida: carreiraPretendida,
    utm_source: pickValue(inputAliases.utm_source || []),
    utm_medium: pickValue(inputAliases.utm_medium || []),
    utm_campaign: pickValue(inputAliases.utm_campaign || []),
    utm_term: pickValue(inputAliases.utm_term || []),
    utm_content: pickValue(inputAliases.utm_content || [])
  };
}

function buildClintPayloads(normalizedPayload, workflowConfig, runExecutionId) {
  const contactFields = cleanObject({
    carreira_pretendida: normalizedPayload.carreira_pretendida
  });

  const contactPayload = cleanObject({
    name: normalizedPayload.nome || (normalizedPayload.email ? normalizedPayload.email.split('@')[0] : `lead-${runExecutionId}`),
    email: normalizedPayload.email,
    ddi: normalizedPayload.ddi,
    phone: normalizedPayload.phone
  });

  if (Object.keys(contactFields).length > 0) {
    contactPayload.fields = contactFields;
  }

  const dealFields = cleanObject({
    utm_source: normalizedPayload.utm_source,
    utm_medium: normalizedPayload.utm_medium,
    utm_campaign: normalizedPayload.utm_campaign,
    utm_term: normalizedPayload.utm_term,
    utm_content: normalizedPayload.utm_content,
    lista_origem: workflowConfig.lista_origem,
    data_importacao: new Date().toISOString(),
    produto: workflowConfig.produto
  });

  const dealPayloadBase = {
    value: workflowConfig.value
  };

  if (Object.keys(dealFields).length > 0) {
    dealPayloadBase.fields = dealFields;
  }

  return {
    contactPayload,
    dealPayloadBase
  };
}

function resolveClintApiToken(headersObject, payloadObject) {
  const tokenHeader = headersObject['x-clint-api-token'] || headersObject['X-CLINT-API-TOKEN'] || headersObject['api-token'] || headersObject['API-TOKEN'] || '';
  const tokenPayload = normalizeValue(payloadObject.clint_api_token || payloadObject.clintToken || '');
  const tokenEnv = (typeof process !== 'undefined' && process?.env)
    ? (process.env.CLINT_API_TOKEN || process.env.CLINT_TOKEN || process.env.API_TOKEN || '')
    : '';

  return normalizeValue(tokenHeader || tokenPayload || tokenEnv);
}

const containers = collectPayloadContainers(payload);
const pickValue = createAliasPicker(containers);
const listResolution = resolveListConfig(pickValue);
const normalizedPayload = buildNormalizedPayload(pickValue, listResolution.input_aliases);
const clintPayloads = buildClintPayloads(normalizedPayload, listResolution.workflow_config, executionId);
const clintApiToken = resolveClintApiToken(headers, payload);
const sanitizedRawPayload = sanitizePayloadForLogs(payload);

const hasContactIdentity = Boolean(normalizedPayload.email || normalizedPayload.phone);

if (!hasContactIdentity) {
  return [
    {
      json: {
        status: 'validation_error',
        code: 'VALIDATION_ERROR',
        message: 'Payload invalido: informe ao menos email ou whatsapp.',
        step: 'validate_payload',
        http_status: 400,
        execution_id: executionId,
        config_version: CONFIG_VERSION,
        should_continue: false,
        list_key: listResolution.list_key,
        requested_list_key: listResolution.requested_list_key,
        list_key_fallback_applied: listResolution.list_key_fallback_applied,
        audit: buildAuditMetadata({
          status: 'validation_error',
          step: 'validate_payload',
          httpStatus: 400,
          listKey: listResolution.list_key,
          extra: {
            sensitive_fields_redacted: true
          }
        }),
        workflow_config: listResolution.workflow_config,
        normalized_payload: sanitizePayloadForLogs(normalizedPayload),
