function buildAuditMetadata({ status, step, httpStatus, extra = {} }) {
  const processedAt = new Date().toISOString();
  const durationMs = Number.isFinite(receivedAtMs)
    ? Math.max(0, Date.parse(processedAt) - receivedAtMs)
    : undefined;

  return cleanObject({
    source: 'manychat_webhook',
    status,
    step,
    http_status: httpStatus,
    execution_id: executionId,
    list_key: listKey,
    config_version: configVersion,
    received_at: receivedAt || undefined,
    processed_at: processedAt,
    duration_ms: durationMs,
    ...extra
  });
}

function buildErrorPayload(code, message, step, httpStatus, details = null, auditExtra = {}) {
  const payload = {
    status: 'integration_error',
    code,
    message,
    step,
    http_status: httpStatus,
    execution_id: executionId,
    list_key: listKey,
    config_version: configVersion,
    requested_list_key: requestedListKey,
    list_key_fallback_applied: listKeyFallbackApplied,
    normalized_payload: sanitizeForLogs(normalizedPayload),
    audit: buildAuditMetadata({
      status: 'integration_error',
      step,
      httpStatus,
      extra: {
        sensitive_fields_redacted: true,
        ...auditExtra
      }
    })
  };

  if (details !== null && details !== undefined) {
    payload.details = sanitizeForLogs(details);
  }

  return [{ json: payload }];
}

function buildDealPayload({
  contactId,
  originId,
  stageId,
  normalizedPayload,
  workflowConfig,
  executionId,
  dealPayloadBase
}) {
  const configuredValue = Number(workflowConfig.value);
  if (!Number.isFinite(configuredValue)) {
    throw Object.assign(new Error('Configuracao invalida: value deve ser numerico.'), {
      step: 'build_deal_payload',
      statusCode: 500,
      details: { value: workflowConfig.value }
    });
  }

  const dealFields = cleanObject(dealPayloadBase.fields || {});
  const titleName = normalizedPayload.nome || normalizedPayload.email || normalizedPayload.phone || `lead-${executionId}`;
  const produto = String(workflowConfig.produto || '').trim();

  const dealPayload = {
    contact_id: contactId,
    origin_id: originId,
    stage_id: stageId,
    title: produto ? `${titleName} - ${produto}` : titleName,
    value: configuredValue,
    fields: dealFields
  };

  if (!Object.keys(dealFields).length) {
    delete dealPayload.fields;
  }

  return dealPayload;
}

const workflowConfig = input.workflow_config || input.fixed_config || {};
const listKey = String(input.list_key || workflowConfig.list_key || '').trim();
const requestedListKey = String(input.requested_list_key || '').trim();
const listKeyFallbackApplied = Boolean(input.list_key_fallback_applied);
const token = String(input.integration_context?.clint_api_token || '').trim();
const baseUrlRaw = String(workflowConfig.clint_base_url || '').trim();
const executionId = input.execution_id || `${Date.now()}`;
const normalizedPayload = input.normalized_payload || {};
const configVersion = String(input.config_version || workflowConfig.config_version || 'wf-c-manychat-intake-clint@fase2-etapa6-2026-03-06').trim();
const receivedAt = String(input.audit?.received_at || '').trim();
const receivedAtMs = receivedAt ? Date.parse(receivedAt) : NaN;

if (!token) {
  return buildErrorPayload(
    'MISSING_CLINT_TOKEN',
    'Token da Clint ausente. Envie x-clint-api-token no header (homologacao) ou configure credencial no n8n.',
    'init_integration',
    500
  );
}

if (!baseUrlRaw) {
  return buildErrorPayload(
    'MISSING_CLINT_BASE_URL',
    'Configuracao invalida: clint_base_url ausente no workflow_config.',
    'init_integration',
    500
  );
}

const baseUrl = baseUrlRaw.replace(/\/$/, '');
const httpRequest = this.helpers.httpRequest.bind(this.helpers);

async function apiRequest(step, method, path, body = undefined) {
  const url = `${baseUrl}${path}`;
  const maxAttempts = 3;

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const options = {
        method,
        url,
        headers: {
          'api-token': token,
          'Content-Type': 'application/json'
        },
        json: true,
        timeout: 20000
      };

      if (body !== undefined) {
        options.body = body;
      }

      return await httpRequest(options);
    } catch (error) {
      const statusCode = error?.statusCode || error?.response?.statusCode || null;
      const shouldRetry = attempt < maxAttempts && (statusCode === 429 || (statusCode >= 500 && statusCode < 600));

      if (shouldRetry) {
        await new Promise((resolve) => setTimeout(resolve, 300 * attempt));
        continue;
      }

      const details = error?.response?.body || error?.message || 'unexpected_error';
      const err = new Error(`Erro na Clint em ${step}: ${method} ${path}`);
      err.step = step;
      err.statusCode = statusCode || 500;
      err.details = details;
      throw err;
    }
  }
}

async function findContactIdByEmail(email) {
  if (!email) {
    return null;
  }

  const emailSearch = await apiRequest('search_contact_email', 'GET', `/contacts?email=${encodeURIComponent(email)}`);
  const contactsByEmail = Array.isArray(emailSearch?.data) ? emailSearch.data : [];
  return contactsByEmail[0]?.id || null;
}

async function findContactIdByPhone(phone) {
  if (!phone) {
    return null;
  }

  const phoneSearch = await apiRequest('search_contact_phone', 'GET', `/contacts?phone=${encodeURIComponent(phone)}`);
  const contactsByPhone = Array.isArray(phoneSearch?.data) ? phoneSearch.data : [];
  return contactsByPhone[0]?.id || null;
}

try {
  const originsResponse = await apiRequest('get_origins', 'GET', '/origins?limit=250');
  const origins = Array.isArray(originsResponse?.data) ? originsResponse.data : [];

  const wantedOriginId = workflowConfig.origin_id;
  const wantedOriginName = String(workflowConfig.origin_name || '').trim().toUpperCase();

  let originResolutionMethod = 'not_found';
  let origin = origins.find((item) => item?.id === wantedOriginId);
  if (origin?.id) {
    originResolutionMethod = 'origin_id';
  } else {
    origin = origins.find((item) => String(item?.name || '').trim().toUpperCase() === wantedOriginName);
    if (origin?.id) {
      originResolutionMethod = 'origin_name';
    }
  }

  if (!origin?.id) {
    throw Object.assign(new Error('Origem alvo nao encontrada na Clint.'), {
      step: 'resolve_origin',
      statusCode: 502,
      details: { wanted_origin_id: wantedOriginId, wanted_origin_name: workflowConfig.origin_name }
    });
  }

  const stages = Array.isArray(origin?.stages) ? origin.stages : [];
  const baseStage = stages.find((stage) => String(stage?.type || '').toUpperCase() === 'BASE') || stages[0];

  if (!baseStage?.id) {
    throw Object.assign(new Error('Stage BASE nao encontrado para a origem informada.'), {
      step: 'resolve_stage',
      statusCode: 502,
      details: { origin_id: origin.id }
    });
  }

  const contactPayloadRaw = Object.assign({}, input.clint_payloads?.contactPayload || {});
  const contactPayload = ensureFieldsObject(cleanObject(contactPayloadRaw));

  let contactId = await findContactIdByPhone(normalizedPayload.phone);
  if (!contactId) {
    contactId = await findContactIdByEmail(normalizedPayload.email);
  }

  let contactOperation = '';
  if (contactId) {
    await apiRequest('update_contact', 'POST', `/contacts/${contactId}`, contactPayload);
    contactOperation = 'updated';
  } else {
    const createdContact = await apiRequest('create_contact', 'POST', '/contacts', contactPayload);
    contactId = extractId(createdContact);

    if (!contactId) {
      throw Object.assign(new Error('Falha ao extrair contact_id apos criar contato.'), {
        step: 'create_contact',
        statusCode: 502,
        details: createdContact
      });
    }

    contactOperation = 'created';
  }

  const tagName = String(workflowConfig.tag_name || '').trim();
  if (tagName) {
    await apiRequest('add_tag', 'POST', `/contacts/${contactId}/tags`, [tagName]);
  }

  const dealPayloadBase = input.clint_payloads?.dealPayloadBase || {};
  const dealPayload = buildDealPayload({
    contactId,
    originId: origin.id,
    stageId: baseStage.id,
    normalizedPayload,
    workflowConfig,
    executionId,
    dealPayloadBase
  });

  const createdDeal = await apiRequest('create_deal', 'POST', '/deals', dealPayload);
  const dealId = extractId(createdDeal);

  return [{
    json: {
      status: 'success',
      code: 'OK',
      message: 'Lead processado com sucesso na Clint.',
      step: 'done',
      http_status: 200,
      execution_id: executionId,
      list_key: listKey,
      config_version: configVersion,
      requested_list_key: requestedListKey,
      list_key_fallback_applied: listKeyFallbackApplied,
      contact_id: contactId,
      contact_operation: contactOperation,
      deal_id: dealId,
      origin_id: origin.id,
      stage_id: baseStage.id,
      tag_name: tagName,
      normalized_payload: normalizedPayload,
      audit: buildAuditMetadata({
        status: 'success',
        step: 'done',
        httpStatus: 200,
        extra: {
          contact_operation: contactOperation,
          origin_resolution: originResolutionMethod,
          dedupe_strategy: 'phone_then_email',
          retries_enabled: true
        }
      })
    }
  }];
} catch (error) {
  const httpStatus = Number(error?.statusCode || 502);
  return buildErrorPayload(
    'CLINT_INTEGRATION_ERROR',
    error?.message || 'Falha de integracao com a Clint.',
    error?.step || 'unknown_step',
    httpStatus >= 400 && httpStatus < 600 ? httpStatus : 502,
    error?.details || null,
    {
      retries_enabled: true
    }
  );
}

const status = String($json.status || '').trim().toLowerCase();

if (status && status !== 'success') {
  const code = String($json.code || 'WORKFLOW_ERROR');
  const message = String($json.message || 'Falha no workflow');
  throw new Error(`${code}: ${message}`);
}

return [{ json: $json }];
